TITLE = '婚活費用計算【無料】マッチングアプリ・結婚相談所 総額いくら？'
DESCRIPTION = '婚活方法・期間・交際費用を入力して総費用を無料計算。方法別の費用比較と節約アドバイス付き。'
JS_CODE = 'var methodCosts = {\n  app:    { monthly: 3000, init: 0, name: "マッチングアプリ" },\n  party:  { monthly: 10000, init: 0, name: "婚活パーティ" },\n  agency: { monthly: 30000, init: 200000, name: "結婚相談所" },\n  mix:    { monthly: 15000, init: 50000, name: "複合婚活" }\n};\n\nvar appAffiliate = \'<div class="bg-pink-50 border border-pink-200 rounded-xl p-4 mb-2"><div class="font-bold text-pink-800 mb-1">妊活中のご夫婦へ</div><p class="text-xs text-gray-600 mb-3">100%天然成分・日本製。妊活中に選ばれる潤滑ゼリー。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ8+9A2HPM+3PXO+5ZMCI" target="_blank" rel="nofollow" class="block text-center bg-pink-500 text-white font-bold py-3 rounded-lg text-sm hover:bg-pink-600 transition">妊活をサポート【ベイビーサポート】 →</a><img border="0" width="1" height="1" src="https://www12.a8.net/0.gif?a8mat=4B3WJ8+9A2HPM+3PXO+5ZMCI" alt="" loading="lazy"></div>\';\nvar agencyAffiliate = \'<div class="bg-pink-50 border border-pink-200 rounded-xl p-4 mb-2"><div class="font-bold text-pink-800 mb-1">結婚相談所の無料カウンセリング</div><p class="text-xs text-gray-600 mb-3">プロのカウンセラーによるサポートで成婚率アップ。まず無料相談から。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ8+9A2HPM+3PXO+5ZMCI" rel="nofollow" target="_blank" rel="noopener sponsored" class="block text-center bg-pink-500 text-white font-bold py-3 rounded-lg text-sm hover:bg-pink-600 transition">無料カウンセリングを予約 →</a></div>\';\n\nfunction calculate() {\n  var method = document.getElementById(\'method\').value;\n  var months = parseInt(document.getElementById(\'months\').value) || 12;\n  var dateCost = (parseFloat(document.getElementById(\'date-cost\').value)||3) * 10000;\n  var fashionCost = (parseFloat(document.getElementById(\'fashion-cost\').value)||1) * 10000;\n\n  var mc = methodCosts[method];\n  var serviceCost = mc.init + mc.monthly * months;\n  var totalDate = dateCost * months;\n  var totalFashion = fashionCost * months;\n  var total = serviceCost + totalDate + totalFashion;\n\n  document.getElementById(\'r-total\').textContent = Math.round(total/10000) + \'万円\';\n  document.getElementById(\'r-period\').textContent = months + \'ヶ月間の目安（\' + mc.name + \'）\';\n  document.getElementById(\'r-service\').textContent = Math.round(serviceCost/10000) + \'万円\';\n  document.getElementById(\'r-date\').textContent = Math.round(totalDate/10000) + \'万円\';\n  document.getElementById(\'r-fashion\').textContent = Math.round(totalFashion/10000) + \'万円\';\n\n  var max = Math.max(serviceCost, totalDate, totalFashion, 1);\n  document.getElementById(\'bar-service\').style.width = Math.round(serviceCost/max*100) + \'%\';\n  document.getElementById(\'bar-date\').style.width = Math.round(totalDate/max*100) + \'%\';\n  document.getElementById(\'bar-fashion\').style.width = Math.round(totalFashion/max*100) + \'%\';\n\n  var adviceEl = document.getElementById(\'r-advice\');\n  var monthlyCost = Math.round(total/months/10000*10)/10;\n  if(method===\'agency\') {\n    adviceEl.textContent = \'💡 結婚相談所は初期費用が高めですが、プロのサポートで成婚率が高い傾向があります。月あたり\'+monthlyCost+\'万円の投資として考えましょう。\';\n  } else if(method===\'app\') {\n    adviceEl.textContent = \'💡 マッチングアプリは最もコスパが良い婚活手段。月\'+monthlyCost+\'万円程度で始められます。写真・プロフィールの質を高めると成功率が上がります。\';\n  } else {\n    adviceEl.textContent = \'💡 月あたりの婚活コストは約\'+monthlyCost+\'万円です。コストを意識しながら効率的な婚活を心がけましょう。\';\n  }\n\n  document.getElementById(\'results\').style.display = \'block\';\n  document.getElementById(\'affiliate-section\').style.display = \'block\';\n  document.getElementById(\'aff-area\').innerHTML = method===\'agency\' ? agencyAffiliate : appAffiliate;\n  document.getElementById(\'results\').scrollIntoView({behavior:\'smooth\'});\n}'
